VALUES
  ('cpa-moex-01291', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲牧場專門飼養牛隻販售，20X2/10/31母牛生下5頭小牛，這5頭小牛的公允價值為$80,000，但若 要出售須完成檢疫等程序，須花費$6,000，若將這些小牛養一年再販售則可售得$400,000（但還要支付 運費$7,000），若年折現率為10%，則甲牧場20X2/10/31應認列「當期原始認列生物資產之利益」 金額為：', '["損失$74,000", "利益$74,000", "損失$357,272", "利益$357,272"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01292', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '20X1年香蕉價格急跌，假設政府為提高種植香蕉農戶所得，規定只要種植香蕉滿6個月，年底每公 頃可向農政單位申請補貼$20,000。某農場有4公頃土地種植香蕉，至年底已種植7個月，若每公頃 香蕉的種植成本$20,000，公允價值為$18,000，出售成本約$2,000，則該農場當年底可以承認的政府 補貼收益為：', '["$0", "$16,000", "$64,000", "$80,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01293', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年1月1日買入一張面額$100,000乙公司公司債，票面利率5%，每年6月30日與 12月31日付息，於20X3年12月31日到期，有效利率為4%，另支付手續費0.3%，甲公司對此債券 投資以公允價值衡量認列。則此債券投資原始入帳金額為多少？（請依四捨五入計算至整數位。 2%，6期之複利現值為0.887971；2%，6期之年金現值為5.601431；2.5%，6期之複利現值為0.862297；', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01294', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '5%，6期之年金現值為5.508125）', '["$102,357", "$102,664", "$102,801", "$103,109"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01295', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '新莊公司於金融海嘯期間簽約承租一間店面，租期十年。租金支付方式：前二年每月月底支付租金 100萬元，每兩年調增租金10萬元，即第三年之月租金為110萬元，第五年之月租金為120萬元， 以此類推。出租人同意免收前六個月租金，即第七個月起支付月租金 100 萬元。新莊公司第七個月 支付租金時，應認列租金費用為：', '["$500,000", "$1,000,000", "$1,150,000", "$1,600,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01296', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '忠孝公司於20X1年12月30日以每張$95,000買入仁愛公司發行的公司債10張，交易手續費為交易 價格的0.1%，20X1年12月31日會計期間結束日時仁愛公司每張市價$98,000，20X2年1月2日交 割，當日仁愛公司每張市價$95,000。忠孝公司將該債券投資列為持有至到期日金融資產。若忠孝公 司使用交易日會計，則20X1年12月30日分錄為何？', '["無分錄", "持有至到期日金融資產  950,000 手續費  950 應付款項    950,950", "持有至到期日金融資產  950,950 現金    950,950", "持有至到期日金融資產  950,950 應付款項    950,950"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01297', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年1月2日開立票據一紙購買土地，面額$2,000,000，票面利率1%，2年到期，每年 1月1日付息，當時之市場利率為6%。請問甲公司此票據於20X1年12月31日之帳面金額為若干？ （計算至元）', '["$1,816,660", "$1,905,660", "$1,925,660", "$2,000,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01298', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '20X7年甲公司被控而成為訴訟案的被告。依據甲公司律師的估計，甲公司於20X7年12月31日認列 $50,000的負債準備。於20X8年11月，法院判甲公司勝訴，原告應賠償甲公司$30,000的訴訟費用， 但原告決定提起上訴，而甲公司律師無法預測上訴後的結果。請問就此一訴訟案件，甲公司於20X8年 12月31日資產負債表中應如何列示？', '["應認列資產$30,000及負債$50,000", "應認列資產$30,000及負債$0", "應認列資產$0及負債$20,000", "應認列資產$0及負債$0"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01299', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '臺北公司與中華租賃公司簽訂租賃合約，自20X1年1月1日起租用機器一部，租期五年，每年年底 支付租金300,000元；該租賃符合融資租賃之條件。20X2年底因物價上漲，雙方同意修改租約，自 20X2年起租金調為400,000元。此租賃協議修改時承租人與出租人應作之會計處理為： 承租人                出租人', '["借記變更租約損失      貸記變更租約利益", "借記租賃資產          貸記變更租約利益", "借記變更租約損失      貸記未賺得融資收益", "借記租賃資產          無"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01300', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '忠孝公司於第1年初向仁愛公司承租一部機器，租期三年，每年年初付租金$300,000。第三年年底， 該機器的估計殘值為$100,000，忠孝公司保證其殘值為$60,000。該機器在租賃開始日之公允價值為 $895,793。簽約時承租人增額借款利率為 12%，租賃隱含利率為 10%。租賃期間該機器之保險、修 理等費用估計每年為$5,000，由忠孝公司負擔。已知此一租賃安排對雙方而言皆符合融資租賃條件。 忠孝公司之租賃資產於租賃期間開始日應表達之金額為：（請依四捨五入計算至整數位。 三期折現因子到期年金現值：10%＝2.7355，12%＝2.6901，複利現值：10%＝0.7513，12%＝0.7118）', '["$865,741", "$895,793", "$960,000", "$1,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
